class Solution {
public:
    string robotWithString(string s) {
        string t, p;
        int minChar = 'z' + 1;
        for (int i = s.size() - 1; i >= 0; --i) {
            minChar = min(minChar, s[i]);
            s[i] = minChar;
        }
        for (char c : s) {
            t += c;
            while (!t.empty() && t.back() <= s.back()) {
                p += t.back();
                t.pop_back();
            }
            s.pop_back();
        }
        return p;
    }
};
